{
  args: {
    logoWidth: 100
  },
  render: function Render(rest) {
    const sanofiLogo = useGetSanofiLogo(rest.isBackgroundBranded);
    const [isMenuOpen, setIsMenuOpen] = useState(false);

    // Helper function to override sectionSize to 12 for mobile menu
    const overrideSectionSize = (item: MenuItem): MenuItem => {
      if (!item.content) return item;
      return {
        ...item,
        content: {
          ...item.content,
          sectionSize: 12,
          sectionContent: item.content.sectionContent.map(subItem => overrideSectionSize(subItem))
        }
      };
    };
    const mobileMenuData = sanofiMenu.map(overrideSectionSize);
    const MobileMenuContent = () => <Grid.Root>
        <CascadingMenu.Root>
          {mobileMenuData.map(item => renderMenuItem(item))}
        </CascadingMenu.Root>
      </Grid.Root>;
    return <ThemeProvider theme={AppTheme.VACCINESHOP}>
        <div className={styles.vaccineShopWrapper}>
          <NavigationHeader.Root burgerMd logo={<div className={styles.logo}>
                <Image src={sanofiLogo} alt="Sanofi logo" height="20px" />
                <Divider orientation={DividerOrientation.VERTICAL} />
                <Image src={\`\${SANOFI_ELEMENTS_CDN_URL}/brand-logos/vaccine-shop.svg\`} alt="Vaccineshop logo" height="32px" />
              </div>} mobileMenuIcon={<MegaMenu.Trigger menuContent={<MobileMenuContent {...rest} />} hasActiveShadow onOpen={() => setIsMenuOpen(true)} onClose={() => setIsMenuOpen(false)}>
                <ButtonIcon icon={isMenuOpen ? IconName.CLOSE : IconName.MENU} size={ButtonSize.SMALL} variant={ButtonVariant.TERTIARY} inverse={rest.isBackgroundBranded} />
              </MegaMenu.Trigger>} subHeader={<>
                {mobileMenuData.map(section => <NavigationHeader.Item key={section.id}>
                    <Menu>
                      <Menu.Trigger>
                        <NavigationHeader.Action>
                          {section.label} <Menu.Item.Icon name="expand_more" />
                        </NavigationHeader.Action>
                      </Menu.Trigger>
                      <Menu.Dropdown>
                        {section.content?.sectionContent?.map(subsection => subsection.content ? <Menu.SubMenu key={subsection.id} label={subsection.label} data-testid="sub-menu-item-xxx">
                              {subsection.content?.sectionContent?.map(item => <Menu.Item key={item.id}>
                                    <span>
                                      <Typography noLineHeight variant={TypographyVariant.BODY_MEDIUM}>
                                        {item.label}
                                      </Typography>
                                    </span>
                                  </Menu.Item>)}
                            </Menu.SubMenu> : <Menu.Item key={subsection.id}>
                              <span>
                                <Typography noLineHeight variant={TypographyVariant.BODY_MEDIUM}>
                                  {subsection.label}
                                </Typography>
                              </span>
                            </Menu.Item>)}
                      </Menu.Dropdown>
                    </Menu>
                  </NavigationHeader.Item>)}
              </>} contained {...rest}>
            <NavigationHeader.CenterContent>
              <SearchInput placeholder="Search" size={InputSize.MEDIUM} classNames={{
              wrapper: styles.searchInput
            }} variant={SearchInputVariant.SUBMIT} />
            </NavigationHeader.CenterContent>
            <NavigationHeader.EndContent>
              <NavigationHeader.Item>
                <Button label="Register" variant={ButtonVariant.SECONDARY} className={styles.nowrapButton} />
              </NavigationHeader.Item>
              <NavigationHeader.Item>
                <Button label="Log in" variant={ButtonVariant.PRIMARY} className={styles.nowrapButton} />
              </NavigationHeader.Item>
            </NavigationHeader.EndContent>
          </NavigationHeader.Root>
        </div>
      </ThemeProvider>;
  }
}
